<?php
declare(strict_types=1);
require_once dirname(__DIR__).'/includes/cms.php';
$pdo=obtenerConexion();$capId=cmsId($_GET['capacitacion_id']??0);$estado=in_array($_GET['estado']??'', ['pendiente_asignacion','inscrito','retirado','finalizado'],true)?$_GET['estado']:'';$buscar=trim((string)($_GET['q']??''));$where=['1=1'];$params=[];if($capId){$where[]='i.asignatura_id=:a';$params['a']=$capId;}if($estado){$where[]='i.estado=:estado';$params['estado']=$estado;}if($buscar!==''){$where[]='(u.nombre LIKE :q OR u.apellido LIKE :q OR u.correo LIKE :q)';$params['q']='%'.$buscar.'%';}$q=$pdo->prepare("SELECT i.*,a.nombre capacitacion,u.nombre,u.apellido,u.correo,s.codigo seccion,CONCAT(d.nombre,' ',d.apellido) docente FROM inscripciones_capacitacion i JOIN asignaturas a ON a.id=i.asignatura_id JOIN usuarios u ON u.id=i.usuario_id LEFT JOIN capacitacion_secciones s ON s.id=i.seccion_id LEFT JOIN usuarios d ON d.id=i.docente_id WHERE ".implode(' AND ',$where)." ORDER BY a.nombre,s.codigo,u.apellido,u.nombre");$q->execute($params);$filas=$q->fetchAll();$caps=$pdo->query("SELECT id,nombre FROM asignaturas WHERE deleted_at IS NULL ORDER BY nombre")->fetchAll();$secciones=$pdo->query("SELECT id,asignatura_id,codigo,cantidad_actual,capacidad_maxima FROM capacitacion_secciones WHERE estado='abierta' AND cantidad_actual<capacidad_maxima ORDER BY codigo")->fetchAll();
cmsCabecera('Estudiantes inscritos','capacitaciones/inscripciones.php','Búsqueda, filtros, cupos y movimientos con historial.');
?><div class="card card-rounded mb-4"><div class="card-body"><form class="row g-3"><div class="col-md-4"><input class="form-control" name="q" value="<?=atenea_e($buscar)?>" placeholder="Nombre o correo"></div><div class="col-md-3"><select class="form-select" name="capacitacion_id"><option value="">Todas</option><?php foreach($caps as$c):?><option value="<?=$c['id']?>" <?=$capId===$c['id']?'selected':''?>><?=atenea_e($c['nombre'])?></option><?php endforeach;?></select></div><div class="col-md-3"><select class="form-select" name="estado"><option value="">Todos los estados</option><?php foreach(['pendiente_asignacion','inscrito','retirado','finalizado'] as$v):?><option value="<?=$v?>" <?=$estado===$v?'selected':''?>><?=atenea_e($v)?></option><?php endforeach;?></select></div><div class="col-md-2"><button class="btn btn-primary text-white w-100">Filtrar</button></div></form></div></div><div class="card card-rounded"><div class="card-body"><div class="table-responsive"><table class="table align-middle"><thead><tr><th>Alumno</th><th>Capacitación</th><th>Sección/docente</th><th>Estado</th><th>Mover o asignar</th></tr></thead><tbody><?php foreach($filas as$f):?><tr><td><strong><?=atenea_e(trim($f['nombre'].' '.$f['apellido']))?></strong><br><small><?=atenea_e($f['correo'])?></small></td><td><?=atenea_e($f['capacitacion'])?></td><td><?=atenea_e(($f['seccion']?:'Sin sección').' · '.($f['docente']?:'Sin docente'))?></td><td><?=atenea_e($f['estado'])?></td><td><form class="d-flex gap-2" method="post" action="inscripcion-accion.php"><input type="hidden" name="csrf_token" value="<?=atenea_e(obtenerTokenCsrf())?>"><input type="hidden" name="inscripcion_id" value="<?=$f['id']?>"><select class="form-select form-select-sm" name="seccion_id" required><option value="">Destino</option><?php foreach($secciones as$s):if($s['asignatura_id']!=$f['asignatura_id'])continue;?><option value="<?=$s['id']?>"><?=atenea_e($s['codigo'])?> (<?=$s['cantidad_actual']?>/<?=$s['capacidad_maxima']?>)</option><?php endforeach;?></select><input class="form-control form-control-sm" name="motivo" maxlength="500" placeholder="Motivo" required><button class="btn btn-sm btn-outline-primary">Guardar</button></form></td></tr><?php endforeach;?><?php if(!$filas):?><tr><td colspan="5" class="text-center py-5">No hay inscripciones.</td></tr><?php endif;?></tbody></table></div></div></div><?php cmsPie();
